document.addEventListener("DOMContentLoaded",()=>{if(window.lucide)lucide.createIcons();const token=localStorage.getItem("GetOTTs_customer_token");const user=JSON.parse(localStorage.getItem("GetOTTs_customer"));if(!token||!user){window.location.href="login";return}let displayName=user.name||"User";let rawPhone=user.phone||"";const cleanDigits=rawPhone.replace(/\D/g,"");const isLID=cleanDigits.length>13;if(isLID)rawPhone="";if(displayName.startsWith("WA-User-")||isLID&&displayName===cleanDigits){displayName=rawPhone?rawPhone:user.name&&!user.name.startsWith("WA-User-")?user.name:"Customer"}let displayPhone=rawPhone;if(displayPhone&&displayPhone.length>6){const clean=displayPhone.replace(/\D/g,"");if(clean.length===12){displayPhone=`+${clean.slice(0,2)} ${clean.slice(2,7)} ${clean.slice(7)}`}else if(clean.length===10){displayPhone=`+91 ${clean.slice(0,5)} ${clean.slice(5)}`}}const displayEmail=!user.email||user.email.startsWith("wa_")?"":user.email;document.getElementById("headerName").textContent=displayName;document.getElementById("profileName").textContent=displayName;const phoneEl=document.getElementById("profilePhone");if(phoneEl)phoneEl.textContent=displayPhone||"";const emailEl=document.getElementById("profileEmail");if(emailEl)emailEl.textContent=displayEmail||"No email added";const welcomeEl=document.getElementById("welcomeMsg");if(welcomeEl){const hour=(new Date).getHours();let greeting="Good evening";if(hour<12)greeting="Good morning";else if(hour<17)greeting="Good afternoon";welcomeEl.textContent=`${greeting}, ${displayName.split(" ")[0]}! 👋`}const profilePhoneInput=document.getElementById("profilePhoneInput");if(profilePhoneInput)profilePhoneInput.textContent=displayPhone||"Not available";const profileEmailInput=document.getElementById("profileEmailInput");if(profileEmailInput)profileEmailInput.value=displayEmail;const refCode=user.referral_code||btoa(user.email||user.phone||"USER").slice(0,8).toUpperCase();const refLinkEl=document.getElementById("refLink");if(refLinkEl)refLinkEl.value=`${window.location.origin}/register?ref=${refCode}`;loadDashboardData(user.id);loadReferralData(user.id);setTimeout(()=>{if(window.lucide)lucide.createIcons()},100)});async function logoutCustomer(){const C=window.GETOTTS_CONFIG;if(C&&C.SUPABASE_URL&&C.SUPABASE_ANON_KEY&&window.supabase){try{const sb=window.supabase.createClient(C.SUPABASE_URL,C.SUPABASE_ANON_KEY);await sb.auth.signOut()}catch(e){}}localStorage.removeItem("GetOTTs_customer_token");localStorage.removeItem("GetOTTs_customer");window.location.href="login"}function switchTab(tabId){document.querySelectorAll(".dash-tab").forEach(t=>t.classList.remove("active"));document.querySelectorAll(".nav-item").forEach(b=>b.classList.remove("active"));document.getElementById("tab-"+tabId).classList.add("active");const navBtn=document.querySelector(`[data-tab="${tabId}"]`);if(navBtn)navBtn.classList.add("active");setTimeout(()=>{if(window.lucide)lucide.createIcons()},50)}function copyReferral(){const input=document.getElementById("refLink");input.select();document.execCommand("copy");const btn=input.nextElementSibling;const oldText=btn.innerHTML;btn.innerHTML="Copied! ✓";btn.style.background="#16a34a";setTimeout(()=>{btn.innerHTML=oldText;btn.style.background=""},2e3)}async function updateProfileEmail(){const emailInput=document.getElementById("profileEmailInput").value.trim();const msgBox=document.getElementById("profileUpdateMsg");if(!emailInput||!emailInput.includes("@")){msgBox.style.color="#dc2626";msgBox.textContent="Please enter a valid email address.";return}msgBox.style.color="var(--gray-500)";msgBox.textContent="Updating...";const user=JSON.parse(localStorage.getItem("GetOTTs_customer"));user.email=emailInput;localStorage.setItem("GetOTTs_customer",JSON.stringify(user));const emailEl=document.getElementById("profileEmail");if(emailEl)emailEl.textContent=emailInput;msgBox.style.color="#16a34a";msgBox.textContent="✓ Email updated successfully!";setTimeout(()=>{msgBox.textContent=""},3e3)}async function loadDashboardData(customerId){const API_BASE=window.GETOTTS_CONFIG&&window.GETOTTS_CONFIG.API_BASE||"https://api.getotts.com/api/v1";try{const response=await fetch(`${API_BASE}/orders/customer/${customerId}`);if(!response.ok)return;const dbOrders=await response.json();const localOrders=JSON.parse(localStorage.getItem("GetOTTs_orders")||"[]");const displayOrders=dbOrders.map(o=>({orderNumber:o.order_number,product:"Subscription Order",date:o.created_at,amount:o.amount,paymentStatus:o.payment_status.toUpperCase(),deliveryStatus:o.delivery_status.toUpperCase(),isPaid:o.payment_status==="paid"}));const dbIds=new Set(displayOrders.map(o=>o.orderNumber));const missingLocalOrders=localOrders.filter(lo=>!dbIds.has(lo.orderNumber));if(missingLocalOrders.length>0){const fetchedOrders=await Promise.all(missingLocalOrders.map(async lo=>{try{const r=await fetch(`${API_BASE}/orders/${lo.orderNumber}`);if(r.ok){const d=await r.json();return{orderNumber:d.order_number,product:lo.product||"Subscription Order",date:d.created_at,amount:d.amount,paymentStatus:(d.payment_status||"PENDING").toUpperCase(),deliveryStatus:(d.delivery_status||"PENDING").toUpperCase(),isPaid:d.payment_status==="paid"}}}catch(e){}return{orderNumber:lo.orderNumber,product:lo.product||"Subscription Order",date:lo.date,amount:lo.amount,paymentStatus:"PENDING",deliveryStatus:"PENDING",isPaid:false}}));displayOrders.push(...fetchedOrders)}displayOrders.sort((a,b)=>new Date(b.date)-new Date(a.date));const statOrders=document.getElementById("statOrders");if(statOrders)statOrders.textContent=displayOrders.length;const activeCount=displayOrders.filter(o=>o.deliveryStatus==="DELIVERED").length;const statActive=document.getElementById("statActive");if(statActive)statActive.textContent=activeCount;if(displayOrders.length>0){const buildOrderRow=o=>`\n                <div style="display:flex; align-items:center; justify-content:space-between; padding:14px 0; border-bottom:1px solid #f1f5f9;">\n                    <div>\n                        <a href="order?id=${o.orderNumber}" style="font-weight:700; color:#4f46e5; font-size:.9rem; text-decoration:none;">${o.orderNumber}</a>\n                        <div style="font-size:.8rem; color:var(--gray-500); margin-top:2px;">${new Date(o.date).toLocaleDateString("en-IN",{day:"numeric",month:"short",year:"numeric"})}</div>\n                    </div>\n                    <div style="text-align:right;">\n                        <div style="font-weight:700; color:var(--gray-800); margin-bottom:4px;">₹${o.amount}</div>\n                        <span style="display:inline-block; background:${o.isPaid?"#dcfce7":"#fef9c3"}; color:${o.isPaid?"#15803d":"#854d0e"}; padding:3px 10px; border-radius:100px; font-size:.72rem; font-weight:700;">\n                            ${o.paymentStatus}\n                        </span>\n                    </div>\n                </div>\n            `;const recentBody=document.getElementById("recentOrdersBody");if(recentBody){recentBody.innerHTML=displayOrders.slice(0,5).map(buildOrderRow).join("")}const ordersPanel=document.getElementById("ordersPanel");if(ordersPanel){ordersPanel.innerHTML=`\n                    <div class="panel-body">\n                        ${displayOrders.map(buildOrderRow).join("")}\n                    </div>\n                `}}}catch(e){console.error("Dashboard data load error:",e)}}async function loadReferralData(customerId){const API_BASE=window.GETOTTS_CONFIG&&window.GETOTTS_CONFIG.API_BASE||"https://api.getotts.com/api/v1";try{const response=await fetch(`${API_BASE}/customers/${customerId}/referrals`);if(!response.ok)return;const data=await response.json();const statRef=document.getElementById("statReferrals");if(statRef)statRef.textContent=data.referral_count||0;const referralsPanel=document.querySelector("#tab-referral .panel:last-child .panel-body");if(referralsPanel&&data.referrals&&data.referrals.length>0){referralsPanel.innerHTML=data.referrals.map(r=>`\n                <div style="display:flex; align-items:center; justify-content:space-between; padding:12px 0; border-bottom:1px solid #f1f5f9;">\n                    <div>\n                        <div style="font-weight:600; color:var(--gray-800);">${r.name||"Customer"}</div>\n                        <div style="font-size:.8rem; color:var(--gray-500);">Joined ${new Date(r.created_at).toLocaleDateString("en-IN",{day:"numeric",month:"short",year:"numeric"})}</div>\n                    </div>\n                    <span style="display:inline-block; background:#dcfce7; color:#15803d; padding:3px 10px; border-radius:100px; font-size:.72rem; font-weight:700;">\n                        +₹50 Credit\n                    </span>\n                </div>\n            `).join("")}if(data.wallet_balance!==undefined){const walletEl=document.getElementById("walletBalance");if(walletEl)walletEl.textContent=`₹${data.wallet_balance}`}}catch(e){console.warn("Referral data load error:",e)}}